export function getProjectsByHall(hallId: "oasis" | "lumina"): ProjectWithColors[] {
  const colorMap = extractedColors as Record<string, ExtractedColors>;
  return projectsData
    .filter((p) => p.hallId === hallId)
    .map((p) => ({ ...p, colors: colorMap[p.image] ?? FALLBACK_COLORS }));
}
